// Solution Shown In Video

public class Solution {
    HashMap<String, Integer> dp;

    public int findTargetSumWays(int[] nums, int S) {
        dp = new HashMap<>();
        return calculate(nums, 0, 0, S);
    }

    public int calculate(int[] nums, int i, int sum, int S) {
        String s = i + "," + sum;

        if (i == nums.length) {
           return (sum == S)? 1 : 0; 
        }
        if(dp.containsKey(s)){
